import React from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Box,
} from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  temperature: number;
  condition: string;
  icon: string; // Emoji or icon identifier
  humidity: number;
  windSpeed: number;
  windUnit?: string;
  temperatureUnit?: string;
  forecast: ForecastDay[];
}

export default function GeneratedComponent({
  temperature,
  condition,
  icon,
  humidity,
  windSpeed,
  windUnit = 'mph',
  temperatureUnit = '°F',
  forecast,
}: Props) {
  return (
    <Card
      padding={24}
      shadow="md"
      style={{
        background: `linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))`,
      }}
    >
      <Stack direction="vertical" gap={24}>
        {/* Current Weather Section */}
        <Stack direction="vertical" gap={16}>
          {/* Temperature and Icon */}
          <Row align="center" gap={16}>
            <div
              style={{
                fontSize: '64px',
                lineHeight: '1',
              }}
            >
              {icon}
            </div>
            <Stack direction="vertical" gap={4}>
              <Text
                variant="h1"
                style={{
                  fontSize: 'var(--ggui-font-size-4xl, 36px)',
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  color: 'var(--ggui-color-primary-900, #0c4a6e)',
                }}
              >
                {temperature}
                <span style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)' }}>
                  {temperatureUnit}
                </span>
              </Text>
              <Text
                variant="body"
                style={{
                  fontSize: 'var(--ggui-font-size-lg, 18px)',
                  color: 'var(--ggui-color-primary-700, #0369a1)',
                  fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                }}
              >
                {condition}
              </Text>
            </Stack>
          </Row>

          {/* Humidity and Wind Speed */}
          <Row gap={16} justify="between">
            <Box
              padding={12}
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              style={{
                background: 'rgba(255, 255, 255, 0.7)',
                flex: 1,
                textAlign: 'center',
              }}
            >
              <Text
                variant="caption"
                style={{
                  color: 'var(--ggui-color-neutral-500, #6b7280)',
                  fontSize: 'var(--ggui-font-size-xs, 12px)',
                  fontWeight: 'var(--ggui-font-weight-medium, 500)',
                }}
              >
                Humidity
              </Text>
              <Text
                variant="body"
                style={{
                  color: 'var(--ggui-color-primary-700, #0369a1)',
                  fontSize: 'var(--ggui-font-size-xl, 20px)',
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  marginTop: 'var(--ggui-spacing-1, 4px)',
                }}
              >
                {humidity}%
              </Text>
            </Box>

            <Box
              padding={12}
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              style={{
                background: 'rgba(255, 255, 255, 0.7)',
                flex: 1,
                textAlign: 'center',
              }}
            >
              <Text
                variant="caption"
                style={{
                  color: 'var(--ggui-color-neutral-500, #6b7280)',
                  fontSize: 'var(--ggui-font-size-xs, 12px)',
                  fontWeight: 'var(--ggui-font-weight-medium, 500)',
                }}
              >
                Wind Speed
              </Text>
              <Text
                variant="body"
                style={{
                  color: 'var(--ggui-color-primary-700, #0369a1)',
                  fontSize: 'var(--ggui-font-size-xl, 20px)',
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  marginTop: 'var(--ggui-spacing-1, 4px)',
                }}
              >
                {windSpeed} {windUnit}
              </Text>
            </Box>
          </Row>
        </Stack>

        {/* Divider */}
        <div
          style={{
            height: '1px',
            background: 'var(--ggui-color-primary-200, #bae6fd)',
          }}
        />

        {/* 5-Day Forecast */}
        <Stack direction="vertical" gap={12}>
          <Text
            variant="label"
            style={{
              color: 'var(--ggui-color-primary-900, #0c4a6e)',
              fontSize: 'var(--ggui-font-size-sm, 14px)',
              fontWeight: 'var(--ggui-font-weight-semibold, 600)',
              textTransform: 'uppercase',
              letterSpacing: '0.05em',
            }}
          >
            5-Day Forecast
          </Text>

          <Row gap={8} wrap>
            {forecast.map((day, index) => (
              <Box
                key={index}
                padding={12}
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                style={{
                  background: 'rgba(255, 255, 255, 0.8)',
                  flex: '1 1 calc(20% - 8px)',
                  minWidth: '90px',
                  textAlign: 'center',
                  border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                }}
              >
                <Text
                  variant="caption"
                  style={{
                    color: 'var(--ggui-color-primary-800, #075985)',
                    fontSize: 'var(--ggui-font-size-xs, 12px)',
                    fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                  }}
                >
                  {day.day}
                </Text>

                <div
                  style={{
                    fontSize: '28px',
                    lineHeight: '1',
                    margin: 'var(--ggui-spacing-1, 4px) 0',
                  }}
                >
                  {day.icon}
                </div>

                <Stack direction="horizontal" justify="center" gap={4}>
                  <Text
                    variant="caption"
                    style={{
                      color: 'var(--ggui-color-primary-700, #0369a1)',
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      fontWeight: 'var(--ggui-font-weight-bold, 700)',
                    }}
                  >
                    {day.high}°
                  </Text>
                  <Text
                    variant="caption"
                    style={{
                      color: 'var(--ggui-color-neutral-500, #6b7280)',
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                    }}
                  >
                    {day.low}°
                  </Text>
                </Stack>
              </Box>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  condition: 'sunny' | 'cloudy' | 'rainy' | 'snowy' | 'windy' | 'partly-cloudy';
  highTemp: number;
  lowTemp: number;
}

interface Props {
  currentTemp: number;
  condition: 'sunny' | 'cloudy' | 'rainy' | 'snowy' | 'windy' | 'partly-cloudy';
  humidity: number;
  windSpeed: number;
  windUnit?: string;
  tempUnit?: string;
  forecast: ForecastDay[];
  location?: string;
}

const getWeatherEmoji = (condition: string): string => {
  const emojiMap: Record<string, string> = {
    sunny: '☀️',
    cloudy: '☁️',
    'partly-cloudy': '⛅',
    rainy: '🌧️',
    snowy: '❄️',
    windy: '💨',
  };
  return emojiMap[condition] || '🌡️';
};

export default function GeneratedComponent(props: Props) {
  const {
    currentTemp,
    condition,
    humidity,
    windSpeed,
    windUnit = 'mph',
    tempUnit = '°F',
    forecast,
    location = 'Current Location',
  } = props;

  return (
    <Card
      variant="outlined"
      style={{
        padding: 'var(--ggui-spacing-lg, 24px)',
        backgroundColor: 'var(--ggui-bg-secondary, #f5f5f5)',
        borderColor: 'var(--ggui-border-default, #e0e0e0)',
        borderRadius: 'var(--ggui-radius-lg, 12px)',
      }}
    >
      <Stack
        direction="vertical"
        gap="var(--ggui-spacing-md, 16px)"
        style={{
          width: '100%',
        }}
      >
        {/* Header with location */}
        <Text
          variant="body"
          size="sm"
          style={{
            color: 'var(--ggui-text-secondary, #666)',
          }}
        >
          {location}
        </Text>

        {/* Current Temperature Section */}
        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-md, 16px)"
          alignItems="center"
        >
          <div
            style={{
              fontSize: '64px',
              lineHeight: '1',
            }}
          >
            {getWeatherEmoji(condition)}
          </div>
          <Stack direction="vertical" gap="var(--ggui-spacing-xs, 4px)">
            <Text
              variant="heading"
              size="lg"
              style={{
                color: 'var(--ggui-text-primary, #000)',
                fontWeight: '600',
              }}
            >
              {currentTemp}{tempUnit}
            </Text>
            <Text
              variant="body"
              size="sm"
              style={{
                color: 'var(--ggui-text-secondary, #666)',
                textTransform: 'capitalize',
              }}
            >
              {condition.replace('-', ' ')}
            </Text>
          </Stack>
        </Stack>

        {/* Weather Details Grid */}
        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-md, 16px)"
          style={{
            width: '100%',
          }}
        >
          {/* Humidity */}
          <div
            style={{
              flex: 1,
              padding: 'var(--ggui-spacing-md, 16px)',
              backgroundColor: 'var(--ggui-bg-primary, #fff)',
              borderRadius: 'var(--ggui-radius-md, 8px)',
              borderColor: 'var(--ggui-border-subtle, #f0f0f0)',
              borderWidth: '1px',
              borderStyle: 'solid',
            }}
          >
            <Stack direction="vertical" gap="var(--ggui-spacing-xs, 4px)">
              <Text
                variant="body"
                size="xs"
                style={{
                  color: 'var(--ggui-text-secondary, #666)',
                  fontWeight: '500',
                }}
              >
                Humidity
              </Text>
              <Text
                variant="body"
                size="lg"
                style={{
                  color: 'var(--ggui-text-primary, #000)',
                  fontWeight: '600',
                }}
              >
                {humidity}%
              </Text>
            </Stack>
          </div>

          {/* Wind Speed */}
          <div
            style={{
              flex: 1,
              padding: 'var(--ggui-spacing-md, 16px)',
              backgroundColor: 'var(--ggui-bg-primary, #fff)',
              borderRadius: 'var(--ggui-radius-md, 8px)',
              borderColor: 'var(--ggui-border-subtle, #f0f0f0)',
              borderWidth: '1px',
              borderStyle: 'solid',
            }}
          >
            <Stack direction="vertical" gap="var(--ggui-spacing-xs, 4px)">
              <Text
                variant="body"
                size="xs"
                style={{
                  color: 'var(--ggui-text-secondary, #666)',
                  fontWeight: '500',
                }}
              >
                Wind Speed
              </Text>
              <Text
                variant="body"
                size="lg"
                style={{
                  color: 'var(--ggui-text-primary, #000)',
                  fontWeight: '600',
                }}
              >
                {windSpeed} {windUnit}
              </Text>
            </Stack>
          </div>
        </Stack>

        {/* 5-Day Forecast */}
        <Stack direction="vertical" gap="var(--ggui-spacing-sm, 8px)">
          <Text
            variant="body"
            size="sm"
            style={{
              color: 'var(--ggui-text-secondary, #666)',
              fontWeight: '500',
            }}
          >
            5-Day Forecast
          </Text>
          <Stack
            direction="horizontal"
            gap="var(--ggui-spacing-sm, 8px)"
            style={{
              overflowX: 'auto',
              paddingBottom: 'var(--ggui-spacing-xs, 4px)',
            }}
          >
            {forecast.map((day, index) => (
              <div
                key={index}
                style={{
                  flex: '0 0 auto',
                  minWidth: '100px',
                  padding: 'var(--ggui-spacing-md, 16px)',
                  backgroundColor: 'var(--ggui-bg-primary, #fff)',
                  borderRadius: 'var(--ggui-radius-md, 8px)',
                  borderColor: 'var(--ggui-border-subtle, #f0f0f0)',
                  borderWidth: '1px',
                  borderStyle: 'solid',
                  textAlign: 'center',
                }}
              >
                <Stack
                  direction="vertical"
                  gap="var(--ggui-spacing-xs, 4px)"
                  alignItems="center"
                >
                  <Text
                    variant="body"
                    size="xs"
                    style={{
                      color: 'var(--ggui-text-secondary, #666)',
                      fontWeight: '500',
                    }}
                  >
                    {day.day}
                  </Text>
                  <div
                    style={{
                      fontSize: '32px',
                      lineHeight: '1',
                    }}
                  >
                    {getWeatherEmoji(day.condition)}
                  </div>
                  <Stack
                    direction="horizontal"
                    gap="var(--ggui-spacing-xs, 4px)"
                    alignItems="center"
                    justifyContent="center"
                  >
                    <Text
                      variant="body"
                      size="xs"
                      style={{
                        color: 'var(--ggui-text-primary, #000)',
                        fontWeight: '600',
                      }}
                    >
                      {day.highTemp}{tempUnit}
                    </Text>
                    <Text
                      variant="body"
                      size="xs"
                      style={{
                        color: 'var(--ggui-text-secondary, #666)',
                      }}
                    >
                      {day.lowTemp}{tempUnit}
                    </Text>
                  </Stack>
                </Stack>
              </div>
            ))}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Row, Text, Box } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  temperature: number;
  condition: 'sunny' | 'cloudy' | 'rainy' | 'snowy' | 'windy' | 'stormy';
  humidity: number;
  windSpeed: number;
  forecast: ForecastDay[];
  unit?: 'C' | 'F';
  windUnit?: 'mph' | 'kmh';
}

const getWeatherIcon = (condition: string): string => {
  const iconMap: Record<string, string> = {
    sunny: '☀️',
    cloudy: '☁️',
    rainy: '🌧️',
    snowy: '❄️',
    windy: '💨',
    stormy: '⛈️',
  };
  return iconMap[condition] || '🌤️';
};

export default function GeneratedComponent({
  temperature,
  condition,
  humidity,
  windSpeed,
  forecast,
  unit = 'F',
  windUnit = 'mph',
}: Props) {
  const weatherIcon = getWeatherIcon(condition);

  return (
    <Card padding={0} shadow="none" border={false}>
      <Stack direction="vertical" gap={0}>
        {/* Current Weather Section */}
        <Box
          padding="var(--ggui-spacing-4)"
          background="linear-gradient(135deg, var(--ggui-color-primary-500, #0ea5e9), var(--ggui-color-primary-600, #0284c7))"
        >
          <Stack direction="vertical" gap={16} align="center">
            {/* Temperature */}
            <div
              style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-neutral-50, #ffffff)',
                lineHeight: 1,
              }}
            >
              {temperature}°{unit}
            </div>

            {/* Weather Icon and Condition */}
            <Row gap={12} align="center" justify="center">
              <div style={{ fontSize: '32px' }}>{weatherIcon}</div>
              <Text
                variant="body"
                color="var(--ggui-color-neutral-50, #ffffff)"
                weight="medium"
                align="center"
              >
                {condition.charAt(0).toUpperCase() + condition.slice(1)}
              </Text>
            </Row>
          </Stack>
        </Box>

        {/* Stats Section */}
        <Box padding="var(--ggui-spacing-4)">
          <Row gap={16} justify="around" wrap>
            {/* Humidity */}
            <Stack
              direction="vertical"
              gap={4}
              align="center"
              justify="center"
            >
              <Text
                variant="caption"
                color="var(--ggui-color-neutral-500, #6b7280)"
              >
                Humidity
              </Text>
              <Text
                variant="body"
                weight="semibold"
                color="var(--ggui-color-neutral-900, #111827)"
              >
                {humidity}%
              </Text>
            </Stack>

            {/* Wind Speed */}
            <Stack
              direction="vertical"
              gap={4}
              align="center"
              justify="center"
            >
              <Text
                variant="caption"
                color="var(--ggui-color-neutral-500, #6b7280)"
              >
                Wind
              </Text>
              <Text
                variant="body"
                weight="semibold"
                color="var(--ggui-color-neutral-900, #111827)"
              >
                {windSpeed} {windUnit}
              </Text>
            </Stack>
          </Row>
        </Box>

        {/* Divider */}
        <div
          style={{
            height: '1px',
            background: 'var(--ggui-color-neutral-200, #e5e7eb)',
            margin: '0',
          }}
        />

        {/* 5-Day Forecast Section */}
        <Box padding="var(--ggui-spacing-4)">
          <Stack direction="vertical" gap={12}>
            <Text
              variant="label"
              weight="semibold"
              color="var(--ggui-color-neutral-900, #111827)"
            >
              5-Day Forecast
            </Text>

            {/* Forecast Days */}
            <Stack direction="vertical" gap={8}>
              {forecast.map((day, index) => (
                <Row
                  key={index}
                  gap={12}
                  align="center"
                  justify="start"
                  wrap={false}
                >
                  {/* Day Name */}
                  <Text
                    variant="caption"
                    weight="medium"
                    color="var(--ggui-color-neutral-900, #111827)"
                    style={{ minWidth: '50px' }}
                  >
                    {day.day}
                  </Text>

                  {/* Weather Icon */}
                  <div style={{ fontSize: '20px', minWidth: '24px' }}>
                    {day.icon}
                  </div>

                  {/* Temps */}
                  <Text
                    variant="caption"
                    color="var(--ggui-color-neutral-500, #6b7280)"
                    style={{ marginLeft: 'auto' }}
                  >
                    {day.high}° / {day.low}°
                  </Text>
                </Row>
              ))}
            </Stack>
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Row, Text, Box } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  location?: string;
  currentTemp?: number;
  condition?: string;
  icon?: string;
  humidity?: number;
  windSpeed?: number;
  forecast?: ForecastDay[];
}

export default function GeneratedComponent({
  location = 'San Francisco, CA',
  currentTemp = 72,
  condition = 'Partly Cloudy',
  icon = '⛅',
  humidity = 65,
  windSpeed = 12,
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 62 },
    { day: 'Tue', icon: '⛅', high: 73, low: 61 },
    { day: 'Wed', icon: '🌧️', high: 68, low: 58 },
    { day: 'Thu', icon: '☁️', high: 70, low: 60 },
    { day: 'Fri', icon: '☀️', high: 78, low: 64 },
  ],
}: Props) {
  return (
    <Box
      style={{
        width: '100vw',
        height: '100dvh',
        background: 'var(--ggui-color-neutral-50, #f9fafb)',
        padding: 'var(--ggui-spacing-6, 24px)',
        overflow: 'auto',
        display: 'flex',
        flexDirection: 'column',
      }}
    >
      <Stack direction="vertical" gap={24} style={{ flex: 1 }}>
        {/* Header */}
        <div style={{ textAlign: 'center' }}>
          <Text variant="h3" style={{ color: 'var(--ggui-color-neutral-700, #374151)' }}>
            {location}
          </Text>
        </div>

        {/* Current Weather Card */}
        <Card
          padding={32}
          shadow="md"
          style={{
            background: 'linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))',
            border: 'none',
            borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
          }}
        >
          <Stack direction="vertical" gap={20} align="center">
            {/* Temperature with Icon */}
            <div style={{ textAlign: 'center' }}>
              <div
                style={{
                  fontSize: '80px',
                  lineHeight: '1',
                  marginBottom: 'var(--ggui-spacing-4, 16px)',
                }}
              >
                {icon}
              </div>
              <Text
                variant="h1"
                style={{
                  fontSize: 'var(--ggui-font-size-4xl, 36px)',
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  color: 'var(--ggui-color-primary-600, #0284c7)',
                }}
              >
                {currentTemp}°
              </Text>
              <Text
                variant="body"
                style={{
                  fontSize: 'var(--ggui-font-size-lg, 18px)',
                  color: 'var(--ggui-color-neutral-600, #4b5563)',
                  marginTop: 'var(--ggui-spacing-2, 8px)',
                }}
              >
                {condition}
              </Text>
            </div>

            {/* Humidity and Wind Speed */}
            <div
              style={{
                width: '100%',
                borderTop: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                paddingTop: 'var(--ggui-spacing-4, 16px)',
              }}
            />
            <Row gap={24} justify="around" style={{ width: '100%' }}>
              {/* Humidity */}
              <Stack direction="vertical" gap={8} align="center">
                <Text
                  variant="caption"
                  style={{
                    color: 'var(--ggui-color-neutral-500, #6b7280)',
                    fontSize: 'var(--ggui-font-size-sm, 14px)',
                    textTransform: 'uppercase',
                    letterSpacing: '0.05em',
                  }}
                >
                  Humidity
                </Text>
                <Text
                  style={{
                    fontSize: 'var(--ggui-font-size-2xl, 24px)',
                    fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                    color: 'var(--ggui-color-primary-700, #0369a1)',
                  }}
                >
                  {humidity}%
                </Text>
              </Stack>

              {/* Wind Speed */}
              <Stack direction="vertical" gap={8} align="center">
                <Text
                  variant="caption"
                  style={{
                    color: 'var(--ggui-color-neutral-500, #6b7280)',
                    fontSize: 'var(--ggui-font-size-sm, 14px)',
                    textTransform: 'uppercase',
                    letterSpacing: '0.05em',
                  }}
                >
                  Wind Speed
                </Text>
                <Text
                  style={{
                    fontSize: 'var(--ggui-font-size-2xl, 24px)',
                    fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                    color: 'var(--ggui-color-primary-700, #0369a1)',
                  }}
                >
                  {windSpeed} mph
                </Text>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* Forecast Section */}
        <Stack direction="vertical" gap={12}>
          <Text
            variant="h3"
            style={{
              color: 'var(--ggui-color-neutral-700, #374151)',
              fontSize: 'var(--ggui-font-size-lg, 18px)',
              fontWeight: 'var(--ggui-font-weight-semibold, 600)',
            }}
          >
            5-Day Forecast
          </Text>

          {/* Forecast Strip */}
          <Row
            gap={12}
