}

const conditionEmojiMap: Record<string, string> = {
  sunny: '☀️',
  clear: '☀️',
  partlycloudy: '⛅',
  cloudy: '☁️',
  overcast: '☁️',
  rainy: '🌧️',
  rain: '🌧️',
  showers: '🌦️',
  stormy: '⛈️',
  thunderstorm: '⛈️',
  snowy: '❄️',
  snow: '❄️',
  windy: '💨',
  foggy: '🌫️',
  mist: '🌫️',
};

function getConditionEmoji(condition?: string, icon?: string) {
  if (icon && icon.trim()) return icon;
  if (!condition) return '🌤️';
  const normalized = condition.toLowerCase().replace(/\s+/g, '');
  return conditionEmojiMap[normalized] || '🌤️';
}

