import React, { useMemo } from 'react';
import { Card, Stack, Text, Button } from '@ggui-ai/design/primitives';

type WeatherCondition =
  | 'sunny'
  | 'partly-cloudy'
  | 'cloudy'
  | 'rainy'
  | 'stormy'
  | 'snowy'
  | 'foggy'
  | 'windy'
  | 'clear-night';

interface ForecastDay {
  dayName: string;
  condition: WeatherCondition;
  icon?: string;
  highTemp: number;
  lowTemp: number;
}

interface Props {
  temperature: number;
  unit?: 'C' | 'F';
  condition: WeatherCondition;
  conditionLabel?: string;
  conditionIcon?: string;
  humidityPercent: number;
  windSpeed: number;
  windUnit?: 'km/h' | 'mph' | 'm/s';
  forecast: ForecastDay[];
  locationName?: string;
  ariaLabel?: string;
  onForecastDayClick?: (day: ForecastDay, index: number) => void;
}

const CONDITION_ICONS: Record<WeatherCondition, string> = {
  sunny: '☀️',
  'partly-cloudy': '⛅',
  cloudy: '☁️',
  rainy: '🌧️',
  stormy: '⛈️',
  snowy: '❄️',
  foggy: '🌫️',
  windy: '💨',
  'clear-night': '🌙',
};

function toTitleCaseCondition(condition: WeatherCondition): string {
  return condition
    .split('-')
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(' ');
}

export default function GeneratedComponent(props: Props) {
  const {
    temperature,
    unit = 'C',
    condition,
    conditionLabel,
    conditionIcon,
    humidityPercent,
    windSpeed,
    windUnit = 'km/h',
    forecast,
    locationName,
    ariaLabel = 'Current weather card',
    onForecastDayClick,
  } = props;

  const displayConditionLabel = conditionLabel ?? toTitleCaseCondition(condition);

  const mappedConditionIcon = useMemo(
    () => conditionIcon || CONDITION_ICONS[condition] || '🌤️',
    [condition, conditionIcon]
  );

  const clampedHumidity = useMemo(() => {
    if (Number.isNaN(humidityPercent)) return 0;
    return Math.min(100, Math.max(0, humidityPercent));
  }, [humidityPercent]);

  const forecastNormalized = useMemo(() => (forecast || []).slice(0, 5), [forecast]);

  const dividerStyle: React.CSSProperties = {
    height: 1,
    width: '100%',
    background: 'var(--ggui-color-neutral-200, #e5e7eb)',
    marginTop: 8,
    marginBottom: 8,
  };

  return (
    <Card
      padding={24}
      shadow="md"
      border={true}
      role="region"
      aria-label={ariaLabel}
      style={{
        background: 'var(--ggui-color-neutral-50, #f9fafb)',
        borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
      }}
    >
      <Stack direction="vertical" gap={16}>
        {locationName ? (
          <Text
            variant="body"
            weight="semibold"
            style={{ color: 'var(--ggui-color-neutral-900, #111827)' }}
          >
            {locationName}
          </Text>
        ) : null}

        <Stack direction="horizontal" gap={12} justify="between" align="center">
          <Text
            variant="h1"
            weight="bold"
            style={{ color: 'var(--ggui-color-primary-800, #075985)' }}
          >
            {temperature}°{unit}
          </Text>

          <Stack direction="vertical" gap={4} align="center">
            <Text
              variant="h1"
              aria-hidden="true"
              style={{ color: 'var(--ggui-color-primary-600, #0284c7)' }}
            >
              {mappedConditionIcon}
            </Text>
            <Text
              variant="h3"
              weight="semibold"
              style={{ color: 'var(--ggui-color-primary-700, #0369a1)' }}
            >
              {displayConditionLabel}
            </Text>
          </Stack>
        </Stack>

        <Text aria-hidden="true" style={dividerStyle}>
          {' '}
        </Text>

        <Stack direction="horizontal" gap={16} justify="between" align="start" wrap={true}>
          <Stack direction="vertical" gap={4}>
            <Text
              variant="caption"
              weight="medium"
              style={{ color: 'var(--ggui-color-neutral-500, #6b7280)' }}
            >
              Humidity
            </Text>
            <Text
              variant="body"
              weight="semibold"
              style={{ color: 'var(--ggui-color-neutral-900, #111827)' }}
            >
              {Math.round(clampedHumidity)}%
            </Text>
          </Stack>

          <Stack direction="vertical" gap={4}>
            <Text
              variant="caption"
              weight="medium"
              style={{ color: 'var(--ggui-color-neutral-500, #6b7280)' }}
            >
              Wind
            </Text>
            <Text
              variant="body"
              weight="semibold"
              style={{ color: 'var(--ggui-color-neutral-900, #111827)' }}
            >
              {windSpeed} {windUnit}
            </Text>
          </Stack>
        </Stack>

        <Text aria-hidden="true" style={dividerStyle}>
          {' '}
        </Text>

        <Card
          padding={12}
          border={false}
          shadow="none"
          style={{
            borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
            background: 'var(--ggui-color-primary-50, #f0f9ff)',
          }}
        >
          <Stack direction="horizontal" gap={8} justify="between" align="stretch" wrap={true} role="list">
            {forecastNormalized.map((day, index) => {
              const forecastIcon = day.icon || CONDITION_ICONS[day.condition] || '🌤️';
              const safeDayName = day.dayName && day.dayName.trim() ? day.dayName.trim() : 'Day';
              const buttonAria = safeDayName + ' forecast ' + day.highTemp + '°/' + day.lowTemp + '°';

              return (
                <Card
                  key={index}
                  padding={8}
                  border={false}
                  shadow="none"
                  role="listitem"
                  style={{
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    background: 'var(--ggui-color-neutral-50, #f9fafb)',
                    minWidth: 88,
                    flex: '1 1 88px',
                  }}
                >
                  {onForecastDayClick ? (
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => onForecastDayClick(day, index)}
                      aria-label={buttonAria}
                      style={{
                        width: '100%',
                        transition:
                          'color var(--ggui-motion-duration-fast, 120ms) ease, background var(--ggui-motion-duration-fast, 120ms) ease',
                        outline: '2px solid transparent',
                        outlineOffset: 2,
                      }}
                    >
                      <Stack direction="vertical" gap={4} align="center">
                        <Text
                          variant="caption"
                          weight="medium"
                          style={{ color: 'var(--ggui-color-neutral-500, #6b7280)' }}
                        >
                          {safeDayName}
                        </Text>
                        <Text
                          variant="h3"
                          aria-hidden="true"
                          style={{ color: 'var(--ggui-color-primary-600, #0284c7)' }}
                        >
                          {forecastIcon}
                        </Text>
                        <Text
                          variant="caption"
                          weight="semibold"
                          style={{ color: 'var(--ggui-color-neutral-900, #111827)' }}
                        >
                          {day.highTemp}°/{day.lowTemp}°
                        </Text>
                      </Stack>
                    </Button>
                  ) : (
                    <Stack direction="vertical" gap={4} align="center">
                      <Text
                        variant="caption"
                        weight="medium"
                        style={{ color: 'var(--ggui-color-neutral-500, #6b7280)' }}
                      >
                        {safeDayName}
                      </Text>
                      <Text
                        variant="h3"
                        aria-hidden="true"
                        style={{ color: 'var(--ggui-color-primary-600, #0284c7)' }}
                      >
                        {forecastIcon}
                      </Text>
                      <Text
                        variant="caption"
                        weight="semibold"
                        style={{ color: 'var(--ggui-color-neutral-900, #111827)' }}
                      >
                        {day.highTemp}°/{day.lowTemp}°
                      </Text>
                    </Stack>
                  )}
                </Card>
              );
            })}
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}

