                <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">{day.low}°</Text>
              </Stack>
            </Stack>
          ))}
        </Row>
      </Box>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

export interface ForecastDay {
  day: string;
  icon: string;
  low: number;
  high: number;
}

export interface Props {
  /** The city or location name */
  location?: string;
  /** Current temperature value */
  currentTemp?: number | string;
  /** Description of weather (e.g. Sunny) */
  condition?: string;
  /** Icon representation (emoji or icon name) */
  conditionIcon?: string;
  /** Humidity percentage */
  humidity?: number | string;
  /** Wind speed with units */
  windSpeed?: string;
  /** Temperature unit 'C' or 'F' */
  unit?: 'C' | 'F';
  /** 5-day forecast data */
  forecast?: ForecastDay[];
}

const defaultForecast: ForecastDay[] = [
  { day: 'Mon', icon: '☀️', low: 18, high: 26 },
  { day: 'Tue', icon: '🌤️', low: 19, high: 24 },
  { day: 'Wed', icon: '☁️', low: 17, high: 22 },
  { day: 'Thu', icon: '🌦️', low: 16, high: 21 },
  { day: 'Fri', icon: '🌧️', low: 15, high: 19 },
];

/**
 * WeatherCard component displaying current weather conditions and a 5-day forecast.
 */
export default function WeatherCard({
  location = 'San Francisco',
  currentTemp = 22,
  condition = 'Partly Cloudy',
  conditionIcon = '🌤️',
  humidity = 64,
  windSpeed = '12 km/h',
  unit = 'C',
  forecast = defaultForecast,
}: Props) {
  return (
    <Card 
      variant="elevated" 
      aria-label={location}
      style={{ 
        padding: 'var(--ggui-spacing-lg)', 
        maxWidth: '400px', 
        width: '100%',
        backgroundColor: 'var(--ggui-color-bg-card, #ffffff)',
        borderRadius: 'var(--ggui-radius-lg, 12px)',
        boxShadow: 'var(--ggui-shadow-md)',
        border: '1px solid var(--ggui-color-border-subtle, transparent)',
      }}
    >
      <Stack direction="column" gap="lg">
        {/* Header: Location & Weather Status */}
        <Stack direction="row" align="center" justify="space-between">
          <Stack direction="column" gap="none">
            <Text weight="bold" size="lg" color="primary">
              {location}
            </Text>
            <Text color="secondary" size="sm">
              {condition}
            </Text>
          </Stack>
          <Text size="4xl" role="img" aria-label={condition} style={{ lineHeight: 1 }}>
            {conditionIcon}
          </Text>
        </Stack>

        {/* Hero Section: Main Temperature */}
        <Stack direction="row" align="start" justify="center">
          <Text 
            weight="black" 
            size="6xl" 
            style={{ 
              fontSize: '4.5rem', 
              lineHeight: 1,
              color: 'var(--ggui-color-text-primary, #111827)',
              letterSpacing: '-0.02em'
            }}
          >
            {currentTemp}
          </Text>
          <Text 
            weight="bold" 
            size="2xl" 
            style={{ 
              marginTop: 'var(--ggui-spacing-sm, 8px)',
              color: 'var(--ggui-color-text-primary, #111827)'
            }}
          >
            °{unit}
          </Text>
        </Stack>

        {/* Stats Strip: Humidity & Wind */}
        <Stack 
          direction="row" 
          justify="space-around" 
          style={{ 
            padding: 'var(--ggui-spacing-md) 0',
            borderTop: '1px solid var(--ggui-color-border-subtle, #f3f4f6)',
            borderBottom: '1px solid var(--ggui-color-border-subtle, #f3f4f6)'
          }}
        >
          <Stack direction="column" align="center" gap="xs">
            <Text 
              color="secondary" 
              size="xs" 
              weight="bold" 
              style={{ 
                letterSpacing: '0.05em',
                color: 'var(--ggui-color-text-secondary, #6b7280)'
              }}
            >
              HUMIDITY
            </Text>
            <Text weight="bold" size="md">
              {humidity}%
            </Text>
          </Stack>
          <Stack direction="column" align="center" gap="xs">
            <Text 
              color="secondary" 
              size="xs" 
              weight="bold" 
              style={{ 
                letterSpacing: '0.05em',
                color: 'var(--ggui-color-text-secondary, #6b7280)'
              }}
            >
              WIND
            </Text>
            <Text weight="bold" size="md">
              {windSpeed}
            </Text>
          </Stack>
        </Stack>

        {/* 5-Day Forecast Strip */}
        <Stack direction="row" justify="space-between" gap="sm">
          {forecast.slice(0, 5).map((day, index) => (
            <Stack 
              key={day.day + '-' + index} 
              direction="column" 
              align="center" 
              gap="xs" 
              style={{ flex: 1 }}
            >
              <Text 
                size="xs" 
                color="secondary" 
                weight="medium" 
                style={{ color: 'var(--ggui-color-text-secondary, #6b7280)' }}
              >
                {day.day}
              </Text>
              <Text size="lg" role="img" aria-label={day.day}>{day.icon}</Text>
              <Stack direction="column" align="center" gap="none">
                <Text size="xs" weight="bold" style={{ color: 'var(--ggui-color-text-primary, #111827)' }}>
                  {day.high}°
                </Text>
                <Text size="xs" color="secondary" style={{ color: 'var(--ggui-color-text-secondary, #6b7280)' }}>
                  {day.low}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}
